const defaults = {
  summary: '',
  why_it_matters: '',
  topic: 'Other',
  relevance_score: 0,
  keywords: [],
  keep_article: false,
  parse_error: true,
};

return items.map((item, index) => {
  const original = $('Limit to 15 Articles').all()[index]?.json || {};
  const raw = item.json?.choices?.[0]?.message?.content || item.json?.output || '';

  let parsed = { ...defaults };

  try {
    let cleaned = String(raw || '').trim();
    cleaned = cleaned
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/```$/i, '')
      .trim();

    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
      cleaned = cleaned.slice(firstBrace, lastBrace + 1);
    }

    parsed = JSON.parse(cleaned);
  } catch (error) {
    parsed = { ...defaults };
  }

  const relevanceScore = Number(parsed.relevance_score);
  const keywords = Array.isArray(parsed.keywords)
    ? parsed.keywords
    : typeof parsed.keywords === 'string'
      ? parsed.keywords.split(',').map((value) => value.trim()).filter(Boolean)
      : [];

  return {
    json: {
      ...original,
      summary: String(parsed.summary || '').trim(),
      why_it_matters: String(parsed.why_it_matters || '').trim(),
      topic: String(parsed.topic || 'Other').trim() || 'Other',
      relevance_score: Number.isFinite(relevanceScore)
        ? Math.max(0, Math.min(10, relevanceScore))
        : 0,
      keywords,
      keep_article: parsed.keep_article === true,
      parse_error: parsed.parse_error === true ? true : false,
    },
  };
});

const decodeEntities = (text = '') =>
  String(text || '')
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'");

const stripHtml = (text = '') =>
  decodeEntities(text)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

return items
  .map((item) => {
    const source = item.json || {};
    const title = String(source.title || source.headline || '').trim();
    const url = String(source.url || source.link || '').trim();
    const publishedDate = String(
      source.published_date ||
      source.pubDate ||
      source.date ||
      source.report_date ||
      source.recall_initiation_date ||
      source.pubdate ||
      ''
    ).trim();

    const rawText = stripHtml([
      source.raw_text,
      source.description,
      source.summary,
      source.abstract,
      source.why_it_matters,
      source.reason_for_recall,
      source.product_description,
    ]
      .filter(Boolean)
      .join('\n'));

    return {
      json: {
        ...source,
        title,
        url,
        published_date: publishedDate,
        raw_text: rawText,
        source: String(source.source || 'Unknown').trim() || 'Unknown',
        source_type: String(source.source_type || 'other').trim() || 'other',
        source_priority: String(source.source_priority || 'medium').trim() || 'medium',
      },
    };
  })
  .filter((item) => item.json.title || item.json.raw_text || item.json.url);

const pattern = /drug safety|pharmacovigilance|clinical ai|artificial intelligence|precision medicine|clinical trial|clinical trials|fda approval|adverse event|medication safety|drug discovery|biotech|pharma|pharmaceutical|recall|enforcement|contamination|sterility|cgmp|warning letter|mislabel|shortage|quality issue/i;

return items.filter((item) => {
  const article = item.json || {};
  const haystack = `${article.title || ''} ${article.raw_text || ''}`;
  return article.source_type === 'regulatory' || pattern.test(haystack);
});

const result = items[0]?.json?.result;
if (!result) return [];

const uids = Object.keys(result).filter((key) => key !== 'uids');

return uids.map((uid) => {
  const article = result[uid] || {};
  return {
    json: {
      title: article.title || 'No title',
      url: `https://pubmed.ncbi.nlm.nih.gov/${uid}/`,
      source: 'PubMed',
      published_date: article.pubdate || '',
      raw_text: [
        article.title || '',
        article.fulljournalname || '',
        article.pubtype?.join(', ') || '',
        article.pubdate || '',
      ]
        .filter(Boolean)
        .join(' '),
      source_type: 'literature',
      source_priority: 'high',
    },
  };
});

function safe(value) {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return value.filter(v => v !== undefined && v !== null && v !== '').join(', ');
  return String(value).trim();
}

return items.map((item) => {
  const source = item.json || {};
  const openfda = source.openfda || {};

  const brandName =
    openfda.brand_name?.[0] ||
    source.product_description ||
    source.product_type ||
    'FDA Enforcement Report';

  const genericName = openfda.generic_name?.[0] || '';
  const manufacturer = openfda.manufacturer_name?.[0] || source.recalling_firm || '';
  const recallReason = source.reason_for_recall || '';
  const productDescription = source.product_description || '';
  const classification = source.classification || '';
  const reportDate = source.report_date || source.recall_initiation_date || '';
  const eventId = source.event_id || '';
  const recallNumber = source.recall_number || '';
  const ndc = openfda.product_ndc?.[0] || '';

  const title = [
    classification ? `[${classification}]` : '',
    brandName,
    recallReason ? `- ${recallReason}` : ''
  ]
    .join(' ')
    .replace(/\s+/g, ' ')
    .trim();

  const query = recallNumber
    ? `recall_number:"${recallNumber}"`
    : eventId
    ? `event_id:"${eventId}"`
    : ndc
    ? `openfda.product_ndc:"${ndc}"`
    : '';

  const url = query
    ? `https://api.fda.gov/drug/enforcement.json?search=${encodeURIComponent(query)}`
    : 'https://open.fda.gov/apis/drug/enforcement/';

  const rawText = [
    `Product: ${safe(productDescription || brandName)}`,
    genericName ? `Generic: ${safe(genericName)}` : '',
    manufacturer ? `Manufacturer: ${safe(manufacturer)}` : '',
    classification ? `Classification: ${safe(classification)}` : '',
    recallReason ? `Reason: ${safe(recallReason)}` : '',
    source.status ? `Status: ${safe(source.status)}` : '',
    source.country ? `Country: ${safe(source.country)}` : '',
    source.voluntary_mandated ? `Recall Type: ${safe(source.voluntary_mandated)}` : ''
  ]
    .filter(Boolean)
    .join(' | ');

  return {
    json: {
      title: title || 'FDA Enforcement Report',
      url,
      published_date: reportDate,
      raw_text: rawText,
      source: 'FDA',
      source_type: 'regulatory',
      source_priority: 'critical',
      event_id: eventId,
      recall_number: recallNumber,
      classification,
      manufacturer,
      product_description: productDescription,
      reason_for_recall: recallReason,
      status: source.status || '',
      country: source.country || '',
      original_payload: source
    }
  };
});

