const PRIORITY = { critical: 3, high: 2, medium: 1, low: 0, other: 0 };

const normalizeUrl = (value = '') => {
  const raw = String(value || '').trim();
  if (!raw) return '';
  try {
    const u = new URL(raw.replace(/^http:\/\//i, 'https://'));
    ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','fbclid','gclid','mc_cid','mc_eid'].forEach((key) => {
      u.searchParams.delete(key);
    });
    u.hash = '';
    return u.toString().replace(/\/$/, '').toLowerCase();
  } catch {
    return raw.replace(/\/$/, '').toLowerCase();
  }
};

const normalizeText = (value = '') =>
  String(value || '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();

const parseDate = (value = '') => {
  const raw = String(value || '').trim();
  if (!raw) return 0;
  if (/^\d{8}$/.test(raw)) {
    const iso = `${raw.slice(0, 4)}-${raw.slice(4, 6)}-${raw.slice(6, 8)}T00:00:00Z`;
    const ts = Date.parse(iso);
    return Number.isNaN(ts) ? 0 : ts;
  }
  const ts = Date.parse(raw);
  return Number.isNaN(ts) ? 0 : ts;
};

let existingRows = [];
try {
  existingRows = $('Get Existing URLs').all();
} catch (error) {
  existingRows = [];
}

const existingKeys = new Set();
for (const rowItem of existingRows) {
  const row = rowItem.json || {};
  const key =
    normalizeUrl(row.url) ||
    normalizeText(`${row.source || ''} ${row.title || ''}`);
  if (key) existingKeys.add(key);
}

const seenInRun = new Set();
const out = [];

for (const item of items) {
  const article = item.json || {};
  const dedupeKey =
    normalizeUrl(article.url) ||
    normalizeText(`${article.source || ''} ${article.title || ''}`);

  if (!dedupeKey) {
    continue;
  }

  const alreadyInSheet = existingKeys.has(dedupeKey);
  const duplicateInRun = seenInRun.has(dedupeKey);

  if (alreadyInSheet || duplicateInRun) {
    continue;
  }

  seenInRun.add(dedupeKey);

  out.push({
    json: {
      ...article,
      dedupe_key: dedupeKey,
      already_in_sheet: alreadyInSheet,
      duplicate_in_run: duplicateInRun,
    },
  });
}

out.sort((a, b) => {
  const priorityA = PRIORITY[a.json.source_priority] ?? 0;
  const priorityB = PRIORITY[b.json.source_priority] ?? 0;
  if (priorityB !== priorityA) return priorityB - priorityA;
  return parseDate(b.json.published_date) - parseDate(a.json.published_date);
});

return out;

const articles = Array.isArray($json.articles) ? $json.articles : [];
const maxTelegramItems = 5;

const compact = (value = '', max = 220) => {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  return text.length > max ? `${text.slice(0, max - 1)}…` : text;
};

const escapeHtml = (value = '') =>
  String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');

const header = `🧪 Pharma Research Digest\n${$now.toFormat("yyyy-LL-dd HH:mm")}\n\n`;

let message = header;
if (!articles.length) {
  message += 'No new high-priority items found.';
} else {
  const visible = articles.slice(0, maxTelegramItems);
  message += visible
    .map((article, index) => {
      return [
        `${index + 1}. ${article.title || 'No title'}`,
        `📊 Score: ${article.relevance_score ?? 'N/A'}`,
        `🏷 Topic: ${article.topic || 'N/A'}`,
        `🔗 ${article.url || ''}`,
        `📝 ${compact(article.summary || '', 220)}`,
      ].join('\n');
    })
    .join('\n\n');

  if (articles.length > maxTelegramItems) {
    message += `\n\n… and ${articles.length - maxTelegramItems} more item(s) were saved to Google Sheets.`;
  }
}

const emailHtml =
  !articles.length
    ? `<h2>🔬 Pharma Research Digest</h2><p>${$now.toFormat("MMMM d, yyyy HH:mm")}</p><p>No new high-priority items found.</p>`
    : `<h2>🔬 High Priority Pharma Research</h2><p>${$now.toFormat("MMMM d, yyyy HH:mm")}</p>` +
      articles
        .map((article) => {
          return `<div style="margin: 20px 0; padding: 15px; border-left: 4px solid #0066cc;">
            <h3>${escapeHtml(article.title || 'No title')}</h3>
            <p><strong>${escapeHtml(article.topic || 'Other')}</strong> | Relevance: ${escapeHtml(article.relevance_score ?? 'N/A')}/10</p>
            <p>${escapeHtml(article.summary || '')}</p>
            <p><a href="${escapeHtml(article.url || '')}">Read more</a></p>
          </div>`;
        })
        .join('');

return [
  {
    json: {
      message,
      email_html: emailHtml,
      article_count: articles.length,
    },
  },
];

return items.map(item => {
  let keywords = item.json.keywords;

  if (Array.isArray(keywords)) {
    keywords = keywords.join(", ");
  } else if (typeof keywords === "string") {
    keywords = keywords.trim();
  } else {
    keywords = "";
  }

  return {
    json: {
      ...item.json,
      keywords_clean: keywords
    }
  };
});
